import React from 'react';
import './LoginVista.css';
import { FaUser, FaLock } from "react-icons/fa";
import './loader.css';

export class LoginForm extends React.Component {
    constructor(props){
      super(props);
      this.state = {
        username: '',
        password: '',
        isLoading: false, // nuevo estado
      };
  
      this.handleChange = this.handleChange.bind(this);
      this.handleSubmit = this.handleSubmit.bind(this);
    }
  
    handleChange(event) {
      const name = event.target.name;
      const value = event.target.value;
      this.setState({
        [name]: value
      });
    }
  
    handleSubmit(event) {
      event.preventDefault();
      this.setState({ isLoading: true }); // muestra el cargador

      setTimeout(() => {
        this.validateForm();
        this.setState({ isLoading: false }); // oculta el cargador
      }, 5000);
    }

    validateForm() {
      if(this.state.username === "admin" && this.state.password === "admin"){
          window.location.href = "/Tabla"
      }
      else{
          alert("Las credenciales no son válidas");
          this.setState({ isLoading: false }); // oculta el cargador
      }
  }
  
    render() {
        const { isLoading } = this.state;

        return (
            <div className='wrapper'>
                <form onSubmit={this.handleSubmit}>
                    <h1>Login</h1>
                    <div className="input-box">
                        <input name="username" type="text" value={this.state.username} placeholder='  Username ' required
                        onChange={this.handleChange} />
                        <FaUser className='icon'/>
                    </div>
                    <div className="input-box">
                        <input name="password" type="password" value={this.state.password} placeholder='  Password ' required
                        onChange={this.handleChange} />
                        <FaLock className='icon'/>
                    </div>
                    {isLoading ? (
                        <div className="loader">
                            {/* contenido del cargador */}
                        </div>
                    ) : (
                        <button type="submit">
                            <span></span>
                            <span></span>
                            <span></span>
                            <span></span>
                            <span></span>
                            <span>Login</span>
                        </button>
                    )}
                </form>
            </div>
        );
    }
}
